    /// <summary>
    /// Find dimension attribute by Backing entity and Name if needed
    /// </summary>
    /// <param name = "_tableName">TableName of the dimension based on</param>
    /// <param name = "_name">Name of the dimension (optionnal)</param>
    /// <returns></returns>
    public static DimensionAttribute UBSFindByBackingEntity(TableName _tableName, Name _name = "", boolean _forupdate = false)
    {
        DimensionAttribute dimAttr ;

        dimAttr.selectForUpdate(_forupdate) ;

        select firstonly dimAttr
            where        dimAttr.BackingEntityTableName == _tableName
            &&  (        dimAttr.Name                   == _name || !_name) ;

        return dimAttr ;
    }

    public static str UBSGetTableName(str _backingEntityTableName, str _backingEntityValueFieldName)
    {
        DimensionAttribute dimAttr;

        select Name from dimAttr
            where dimAttr.BackingEntityTableName == _backingEntityTableName &&
                  dimAttr.BackingEntityValueFieldName == _backingEntityValueFieldName &&
                  dimAttr.Type == DimensionAttributeType::ExistingList;

        return dimAttr.Name;
    }
